args.command:
node -e "
const Ajv = require('ajv');
const fs = require('fs');

const schema = JSON.parse(fs.readFileSync('schema.json', 'utf8'));
const task = JSON.parse(fs.readFileSync('task.json', 'utf8'));

const ajv = new Ajv();
const validate = ajv.compile(schema);
const valid = validate(task);

console.log('Validation result:', valid ? 'PASS' : 'FAIL');
if (!valid) {
  console.log('Errors:', validate.errors);
}
console.log('Task keys:', Object.keys(task));
console.log('Task content:', JSON.stringify(task, null, 2));
"
